Code:
public boolean xyBalance(String str) {
    boolean sawY = false;

    // iterate from end to start
    for (int i = str.length() - 1; i >= 0; i--) {
        if (str.charAt(i) == 'x') {
            // if we have already seen a 'y', continue
            if (sawY) {
                continue;
            }
            // if we have not seen a 'y', return false
            else {
                return false;
            }
        }
        // if we see a 'y', flag it
        if (str.charAt(i) == 'y') {
            sawY = true;
        }
    }
    return true;
}

