public int makeChocolate(int small, int big, int goal) {
    int remaining = goal;
    int bigCount = big * 5;

    // Use as many big pieces as possible
    while (bigCount > 0 && bigCount <= remaining) {
        remaining -= bigCount;
        big--;
        bigCount = big * 5;
    }

    // Use as many small pieces as possible
    if (remaining <= small) {
        return remaining;
    } else {
        return -1;
    }
}

