public int[] fix45(int[] nums) {
    if (nums == null || nums.length < 2)
        return nums;

    int i = 0;
    int j = 0;

    while (j < nums.length) {
        if (nums[j] != 4 && nums[j] != 5) {
            nums[i] = nums[j];
            i++;
