Code:
public int[] fix45(int[] nums) {
    int n = nums.length;
    int i = 0, j = 0;

    while (j < n) {
        if (nums[j] == 5) {
            while (i < j && nums[i] != 4) {
                i++;
            }
            if (i < j) {
                int temp = nums[i+1];
                nums[i+1] = nums[j];
                nums[j] = temp;
            }
        }
        j++;
    }
    return nums;
}

public int[] tenRun(int[] nums) {
    if(nums == null || nums.length == 0){
        return nums;
    }

    int n = nums.length;
    for(int i = 0; i < n; i++){
        if(nums[i] % 10 == 0){
            int value = nums[i];
            for(int j = i + 1; j < n; j++){
                if(nums[j] % 10 == 0){
                    break;
                }
                nums[j] = value;
            }
        }
    }
    return nums;
}

