public int blackjack(int a, int b)
{

}

Code:
public int blackjack(int a, int b) {
    a = Math.min(a, 21);
    b = Math.min(b, 21);
    if (a > 21 && b > 21) {
        return 0;
    } else {
        return Math.max(a, b);
    }
}

